import heapq

def func(intervals, k):
    # Count frequency of each integer
    freq = {}
    for lst in intervals:
        for num in lst:
            freq[num] = freq.get(num, 0) + 1

    # Use a min-heap of size k to keep top k frequent elements
    heap = []
    for num in freq:
        heapq.heappush(heap, (freq[num], num))
        if len(heap) > k:
            heapq.heappop(heap)

    # Return the top k elements in sorted order
    return sorted([num for _, num in heap])

