from collections import Counter

def func(lists, k):
    if not lists or k <= 0:
        return []

    # Count frequencies of all integers across all lists
    counter = Counter()
    for lst in lists:
        counter.update(lst)

    # If k is greater than or equal to the number of unique integers, return all unique integers
    if k >= len(counter):
        return sorted(counter.keys())

    # Use a min-heap to keep track of the top k most frequent integers
    heap = []

    for num, freq in counter.items():
        if len(heap) < k or freq > heap[0][1]:
            heapq.heappush(heap, (freq, num))
            if len(heap) > k:
                heapq.heappop(heap)

    # Return the top k integers sorted in descending order
    return [num for freq, num in sorted(heap, key=lambda x: x[0], reverse=True)]

